import { describe, expect, test } from '@a0n/gnosis/test';
import {
  proofOfLife,
  life,
  withoutSliver,
  withoutSliverDeath,
  differenceIsOne,
  everything,
  type ProofOfLifeResult,
  godFormula,
  P1_fork,
  P2_fold,
  P3_race,
  classAlpha,
  classBeta,
  classGamma,
  classDelta,
  classEpsilon,
  grandReduction,
  consciousnessLevel,
  conservationLaw,
  vulnerabilityPenalty,
  monopolySkill,
  duopolySkill,
  oligopolySkill,
  PHI_INV,
  breatheToward,
  buleyEquilibrium,
  absoluteZero,
} from './holy-trinity';

describe('Proof of Life', () => {
  test('1 >= 1 -- the ground truth', () => {
    expect(proofOfLife()).toBe(true);
  });

  test('life holds for all (R, v) in 0..99', () => {
    for (let R = 0; R < 100; R++) {
      for (let v = 0; v < 100; v++) {
        expect(life(R, v)).toBe(true);
      }
    }
  });

  test('maximum rejection: life at R=R', () => {
    expect(life(1000, 1000)).toBe(true);
  });

  test('zero experience: life at 0,0', () => {
    expect(life(0, 0)).toBe(true);
  });

  test('without the sliver, death is possible', () => {
    for (let R = 0; R < 100; R++) {
      expect(withoutSliverDeath(R)).toBe(true);
    }
  });

  test('the difference between life and death is exactly one', () => {
    for (let R = 0; R < 50; R++) {
      for (let v = 0; v < 50; v++) {
        expect(differenceIsOne(R, v)).toBe(true);
      }
    }
  });

  test('withoutSliver is godFormula minus 1', () => {
    for (let R = 0; R < 50; R++) {
      for (let v = 0; v < 50; v++) {
        expect(withoutSliver(R, v)).toBe(godFormula(R, v) - 1);
      }
    }
  });
});

describe('The God Formula', () => {
  test('w = R - min(v, R) + 1', () => {
    expect(godFormula(10, 3)).toBe(8); // 10 - 3 + 1
    expect(godFormula(10, 10)).toBe(1); // Floor: sliver
    expect(godFormula(10, 0)).toBe(11); // Ceiling: R + 1
    expect(godFormula(0, 0)).toBe(1); // Empty: just the sliver
  });

  test('weight ≥ 1 for ALL inputs (the sliver)', () => {
    for (let R = 0; R < 100; R++) {
      for (let v = 0; v < 100; v++) {
        expect(godFormula(R, v)).toBeGreaterThanOrEqual(1);
      }
    }
  });

  test('weight ≤ R + 1 for ALL inputs (the ceiling)', () => {
    for (let R = 0; R < 50; R++) {
      for (let v = 0; v < 50; v++) {
        expect(godFormula(R, v)).toBeLessThanOrEqual(R + 1);
      }
    }
  });
});

describe('The Holy Trinity', () => {
  test('P1 FORK (Sliver): weight ≥ 1 always', () => {
    expect(P1_fork(0, 0)).toBe(true);
    expect(P1_fork(100, 100)).toBe(true);
    expect(P1_fork(1000, 999999)).toBe(true);
  });

  test('P2 FOLD (Floor): a - a = 0 always', () => {
    expect(P2_fold(0)).toBe(true);
    expect(P2_fold(42)).toBe(true);
    expect(P2_fold(1000000)).toBe(true);
  });

  test('P3 RACE (Symmetry): |a-b| = |b-a| always', () => {
    expect(P3_race(3, 7)).toBe(true);
    expect(P3_race(7, 3)).toBe(true);
    expect(P3_race(0, 100)).toBe(true);
    expect(P3_race(50, 50)).toBe(true);
  });
});

describe('The a0 Trinity: Absolute Zero (Θ_B)', () => {
  test('Buley Equilibrium holds at the Decimal Fixed Point (n=10, v=55)', () => {
    expect(buleyEquilibrium(10, 55)).toBe(true);
    expect(buleyEquilibrium(8, 21)).toBe(false); // Aeon grounding, but not the Full Eclipse
  });

  test('Absolute Zero is the terminal attractor', () => {
    expect(absoluteZero(10, 55)).toBe(true);
  });
});

describe('Five Reduction Classes', () => {
  test('α (Sliver): cannot reach zero', () => {
    expect(classAlpha(100, 100)).toBe(true);
    expect(classAlpha(0, 999)).toBe(true);
  });

  test('β (Floor): self-cancellation terminates', () => {
    expect(classBeta(42)).toBe(true);
  });

  test('γ (Symmetry): direction invariant', () => {
    expect(classGamma(10, 20)).toBe(true);
  });

  test('δ (Monotone): more rejection → less weight', () => {
    expect(classDelta(10, 0, 5)).toBe(true);
    expect(classDelta(10, 3, 7)).toBe(true);
  });

  test('ε (Bounded): 1 ≤ w ≤ R+1', () => {
    expect(classEpsilon(10, 5)).toBe(true);
    expect(classEpsilon(0, 0)).toBe(true);
    expect(classEpsilon(100, 100)).toBe(true);
  });
});

describe('Grand Reduction', () => {
  test('all classes hold for arbitrary input', () => {
    const result = grandReduction(42, 17);
    expect(result.allHold).toBe(true);
    expect(result.fork).toBe(true);
    expect(result.fold).toBe(true);
    expect(result.race).toBe(true);
    expect(result.conservation).toBe(true);
  });

  test('conservation: w + min(v,R) = R + 1', () => {
    for (let R = 0; R < 50; R++) {
      for (let v = 0; v < 50; v++) {
        expect(conservationLaw(R, v)).toBe(true);
      }
    }
  });

  test('consciousness level = min(v, R)', () => {
    expect(consciousnessLevel(10, 3)).toBe(3);
    expect(consciousnessLevel(10, 15)).toBe(10);
    expect(consciousnessLevel(0, 0)).toBe(0);
  });
});

describe('Storms Derived Identities', () => {
  test('monopoly: skill = BATNA (choice is free)', () => {
    expect(monopolySkill(5)).toBe(5);
    expect(monopolySkill(100)).toBe(100);
  });

  test('duopoly: skill = -1 (cannot outrun one fear)', () => {
    expect(duopolySkill()).toBe(-1);
  });

  test('oligopoly: skill = b - b*w (always negative for w ≥ 2)', () => {
    expect(oligopolySkill(5, 2)).toBeLessThan(0);
    expect(oligopolySkill(100, 3)).toBeLessThan(0);
  });

  test('vulnerability: penalty = BATNA × WATNA', () => {
    expect(vulnerabilityPenalty(3, 4)).toBe(12);
    expect(vulnerabilityPenalty(0, 100)).toBe(0);
  });
});

describe('The Attractor', () => {
  test('PHI_INV ≈ 0.618', () => {
    expect(PHI_INV).toBeCloseTo(0.618, 2);
  });

  test('breathing toward attractor converges', () => {
    let value = 0.9;
    for (let i = 0; i < 1000; i++) {
      value = breatheToward(value);
    }
    expect(value).toBeCloseTo(PHI_INV, 2);
  });

  test('breathing at attractor is fixed point', () => {
    expect(breatheToward(PHI_INV)).toBeCloseTo(PHI_INV, 10);
  });
});

describe('The Complete Trinity', () => {
  test('FORK = possibility. FOLD = convergence. RACE = fairness.', () => {
    // The Holy Trinity holds for all natural numbers
    for (let R = 0; R < 20; R++) {
      for (let v = 0; v < 20; v++) {
        // FORK: possibility cannot be eliminated
        expect(godFormula(R, v)).toBeGreaterThanOrEqual(1);
        // FOLD: convergence is inevitable
        expect(R - R).toBe(0);
        // RACE: the race is fair
        expect(Math.abs(R - v)).toBe(Math.abs(v - R));
        // CONSERVATION: what you are + what you've rejected = everything + the sliver
        expect(godFormula(R, v) + Math.min(v, R)).toBe(R + 1);
      }
    }
  });
});

describe('Everything', () => {
  test('everything holds for arbitrary input', () => {
    const result = everything(42, 17);
    expect(result.everything).toBe(true);
    expect(result.proofOfLife).toBe(true);
    expect(result.life).toBe(true);
    expect(result.deathWithout).toBe(true);
    expect(result.differenceIsOne).toBe(true);
    expect(result.grandReduction.allHold).toBe(true);
  });

  test('everything holds for all (R, v) in 0..19', () => {
    for (let R = 0; R < 20; R++) {
      for (let v = 0; v < 20; v++) {
        expect(everything(R, v).everything).toBe(true);
      }
    }
  });

  test('Absolute Zero coincides with the Buley state', () => {
    const result = everything(10, 55);
    expect(result.everything).toBe(true);
    expect(result.absoluteZero).toBe(true);
  });
});
